// Variants is the resolver for the variants field on Product.
func (r *productResolver) Variants(ctx context.Context, obj *model.Product) ([]*model.Variant, error) {
	var dbVariants []dbmodels.Variant

	// Fetch variants for the given product ID using GORM
	err := r.DB.WithContext(ctx).
		Where("product_id = ?", obj.ID).
		Find(&dbVariants).Error

	if err != nil {
		return nil, fmt.Errorf("failed to fetch variants: %w", err)
	}

	// Map DB models to GraphQL models
	gqlVariants := make([]*model.Variant, len(dbVariants))
	for i, v := range dbVariants {
		gqlVariants[i] = mapDBVariantToGQL(&v)
	}

	return gqlVariants, nil
}

// Product is the resolver for the product query.
func (r *queryResolver) Product(ctx context.Context, id string) (*model.Product, error) {
	var dbProduct dbmodels.Product

	// Fetch a single product by ID
	err := r.DB.WithContext(ctx).
		Where("id = ?", id).
		First(&dbProduct).Error

	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, fmt.Errorf("product with id %s not found", id)
		}
		return nil, fmt.Errorf("failed to fetch product: %w", err)
	}

	return mapDBProductToGQL(&dbProduct), nil
}

