func mapDBProductToGQL(p *dbmodels.Product) *model.Product {
	if p == nil {
		return nil
	}
	
	// Convert description to pointer if it's a string in DB but optional in GQL
	var desc *string
	if p.Description != "" {
		desc = &p.Description
	}

	return &model.Product{
		ID:          p.ID.String(),
		Name:        p.Name,
		Description: desc,
		VendorID:    p.VendorID.String(),
		CreatedAt:   p.CreatedAt.Format("2006-01-02T15:04:05Z"),
		UpdatedAt:   p.UpdatedAt.Format("2006-01-02T15:04:05Z"),
	}
}

func mapDBVariantToGQL(v *dbmodels.Variant) *model.Variant {
	if v == nil {
		return nil
	}
	return &model.Variant{
		ID:                v.ID.String(),
		ProductID:         v.ProductID.String(),
		Sku:               v.SKU,
		Price:             v.Price,
		InventoryQuantity: v.InventoryQuantity,
	}
}
